import React, { useState } from 'react';
import axios from 'axios';

function RegisterComplaint() {
  const [formData, setFormData] = useState({
    title: '', description: '', category: 'Technical', user_id: 1
  });

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      await axios.post('http://127.0.0.1:8000/api/complaints/', formData);
      alert("Shikayat darj ho gayi hai!");
      window.location.reload(); // Data update dikhane ke liye
    } catch (err) {
      alert("Error: Backend se connect nahi ho paya");
    }
  };

  return (
    <div style={{ marginTop: '20px', border: '1px solid #ccc', padding: '15px' }}>
      <h3>Nayi Shikayat Darj Karein</h3>
      <form onSubmit={handleSubmit}>
        <input type="text" placeholder="Title" onChange={e => setFormData({...formData, title: e.target.value})} required /><br/><br/>
        <textarea placeholder="Description" onChange={e => setFormData({...formData, description: e.target.value})} required /><br/><br/>
        <select onChange={e => setFormData({...formData, category: e.target.value})}>
          <option value="Technical">Technical</option>
          <option value="Billing">Billing</option>
          <option value="General">General</option>
        </select><br/><br/>
        <button type="submit" style={{ background: 'green', color: 'white', padding: '10px' }}>Submit</button>
      </form>
    </div>
  );
}

export default RegisterComplaint;
